protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
    // Preserve the old name so existing documents remain queryable.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // EF Core 9 changed id format from "Blog|1" to just "1".
    // Preserve the old compound format so existing documents remain accessible.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // HasIndex was removed — Cosmos DB indexing is managed via the container's
    // indexing policy (Azure Portal / Bicep / Terraform), not EF Core.
    // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
}

